document.addEventListener("DOMContentLoaded",()=>{setTimeout(()=>{document.body.classList.add("page-loaded")},50);document.querySelectorAll(".abcd-letter").forEach(e=>{e.addEventListener("click",e=>{e.preventDefault();const d=e.currentTarget.getAttribute("data-url");d&&t(d)})});const e=document.querySelector('.btn-icon[href="index.html"]');function t(e){document.body.classList.remove("page-loaded"),document.body.classList.add("page-exiting"),setTimeout(()=>{window.location.href=e},400)}e&&e.addEventListener("click",e=>{e.preventDefault(),t("index.html")})});